{"command": "# Check what we actually got from NuGet - it's gzip compressed
curl -sS -H "Accept-Encoding: identity" "https://api.nuget.org/v3/registration5-semver2/microsoft.netcore.app.runtime.android-arm64/index.json" 2>&1 | python3 -c "
import json, sys
data = json.load(sys.stdin)
pages = data.get('items', [])
if pages:
    last_page = pages[-1]
    items = last_page.get('items', [])
    if not items:
        print(f'Need to fetch page: {last_page.get(\"@id\")}')
    else:
        for item in items[-10:]:
            ver = item.get('catalogEntry', {}).get('version', 'unknown')
            print(ver)
" 2>&1", "description": "Query NuGet for available versions", "initial_wait": 15}

{"command": "# Fix encoding
curl -sS --compressed "https://api.nuget.org/v3/registration5-semver2/microsoft.netcore.app.runtime.android-arm64/index.json" 2>&1 | python3 -c "
import json, sys
data = json.loads(sys.stdin.read().encode().decode('utf-8-sig'))
pages = data.get('items', [])
for page in pages[-1:]:
    items = page.get('items', [])
    if not items:
        print(f'Need to fetch: {page.get(\"@id\")}')
    else:
        for item in items[-10:]:
            ver = item.get('catalogEntry', {}).get('version', 'unknown')
            print(ver)
" 2>&1", "description": "Query NuGet versions with fixed encoding", "initial_wait": 15}

{"command": "# Let me list all versions of the CoreCLR android-arm64 runtime package
curl -sS "https://azuresearch-usnc.nuget.org/query?q=Microsoft.Android.Runtime.CoreCLR+android-arm64&take=50" | python3 -c "
import json, sys
data = json.load(sys.stdin)
for item in data.get('data', []):
    if 'arm64' in item['id'] and 'Msi' not in item['id']:
        versions = item.get('versions', [])
        print(f\"{item['id']}: {len(versions)} versions\")
        for v in versions[-5:]:
            print(f\"  {v['version']}\")
" 2>&1", "description": "List all CoreCLR Android arm64 versions", "initial_wait": 10}

